import SwiftUI
import Contacts
import ContactsUI

// REQUIRES PLIST: NSContactsUsageDescription
class ContactsViewModel: ObservableObject {
    private let store = CNContactStore()
    @Published var isAuthorized = false
    @Published var selectedContactName: String?
    @Published var errorMessage: String?

    func requestAccess() {
        store.requestAccess(for: .contacts) { [weak self] granted, _ in
            DispatchQueue.main.async {
                guard let self = self else { return }
                if granted {
                    self.isAuthorized = true
                    self.errorMessage = nil
                } else {
                    self.isAuthorized = false
                    self.errorMessage = "Contacts access denied"
                }
            }
        }
    }

    func setSelectedContact(_ contact: CNContact) {
        let name = [contact.givenName, contact.familyName].filter { !$0.isEmpty }.joined(separator: " ")
        selectedContactName = name.isEmpty ? nil : name
    }
}

struct ContactPickerRepresentable: UIViewControllerRepresentable {
    @Environment(\.dismiss) private var dismiss
    var onSelect: (CNContact) -> Void

    func makeUIViewController(context: Context) -> CNContactPickerViewController {
        let picker = CNContactPickerViewController()
        picker.delegate = context.coordinator
        return picker
    }

    func updateUIViewController(_ uiViewController: CNContactPickerViewController, context: Context) {}

    func makeCoordinator() -> Coordinator { Coordinator(self) }

    class Coordinator: NSObject, CNContactPickerDelegate {
        let parent: ContactPickerRepresentable
        init(_ parent: ContactPickerRepresentable) { self.parent = parent }

        func contactPicker(_ picker: CNContactPickerViewController, didSelect contact: CNContact) {
            DispatchQueue.main.async {
                self.parent.onSelect(contact)
                self.parent.dismiss()
            }
        }

        func contactPickerDidCancel(_ picker: CNContactPickerViewController) {
            DispatchQueue.main.async { self.parent.dismiss() }
        }
    }
}

struct ContactsView: View {
    @StateObject private var viewModel = ContactsViewModel()
    @State private var showPicker = false

    var body: some View {
        VStack(spacing: 16) {
            if let message = viewModel.errorMessage {
                Text(message).foregroundStyle(.red)
            }
            Button("Choose Contact") { showPicker = true }
                .disabled(!viewModel.isAuthorized)
            if let name = viewModel.selectedContactName {
                Text(name)
            }
        }
        .onAppear { viewModel.requestAccess() }
        .sheet(isPresented: $showPicker) {
            ContactPickerRepresentable(onSelect: { viewModel.setSelectedContact($0) })
        }
    }
}
